// Sample review and ranking data — embedded for zero-account testing.
// In production, replace with live HTTP fetches to G2/Capterra pages.
const snapshot = {
  captured_at: new Date().toISOString(),
  companies: [
    {
      name: 'Acme Analytics',
      g2: { rating: 4.6, review_count: 312, category_rank: 3, top_tags: ['easy to use', 'great support', 'good reporting'], recent_reviews: [
        { stars: 5, excerpt: 'Onboarding was fast and the support team responded in hours.', date: '2026-07-10' },
        { stars: 2, excerpt: 'Wish there was a mobile app. Everything else is great.', date: '2026-07-08' }
      ]},
      capterra: { rating: 4.5, review_count: 187, category_rank: 4, recent_reviews: [
        { stars: 5, excerpt: 'Best reporting I have seen in this category.', date: '2026-07-09' }
      ]}
    },
    {
      name: 'CompetitorX',
      g2: { rating: 4.3, review_count: 890, category_rank: 1, top_tags: ['feature-rich', 'steep learning curve', 'expensive'], recent_reviews: [
        { stars: 3, excerpt: 'Good tool but onboarding took us 3 weeks and pricing jumped at renewal.', date: '2026-07-11' }
      ]},
      capterra: { rating: 4.2, review_count: 645, category_rank: 2, recent_reviews: [
        { stars: 2, excerpt: 'Hidden costs in enterprise tier. Watch your contract.', date: '2026-07-07' }
      ]}
    },
    {
      name: 'CompetitorY',
      g2: { rating: 4.5, review_count: 430, category_rank: 2, top_tags: ['affordable', 'simple UI', 'limited integrations'], recent_reviews: [
        { stars: 5, excerpt: 'Perfect for small teams. Simple and affordable.', date: '2026-07-12' }
      ]},
      capterra: { rating: 4.4, review_count: 290, category_rank: 3, recent_reviews: [
        { stars: 4, excerpt: 'Would love more integrations but the core product is solid.', date: '2026-07-06' }
      ]}
    }
  ]
};
return [{ json: snapshot }];

// In a live run (scheduled), fetch real pages here.
// For now, pass through the data from whichever trigger ran.
// Advanced: replace with HTTP Request nodes to G2/Capterra public URLs.
const data = $input.first().json;
if (!data.companies || !Array.isArray(data.companies)) {
  throw new Error('Expected companies array in snapshot data');
}
return [{ json: { ...data, company_count: data.companies.length } }];

const { companies, captured_at } = $input.first().json;

// Compute deltas (in production, compare against previous snapshot stored in Sheets/DB)
// For now, annotate and summarize
const our_company = companies.find(c => c.name === ($env.OUR_COMPANY_NAME || 'Acme Analytics'));
const competitors = companies.filter(c => c.name !== ($env.OUR_COMPANY_NAME || 'Acme Analytics'));

const lines = [
  `REVIEW PLATFORM TRACKER — ${new Date(captured_at).toDateString()}`,
  ``,
  `OUR POSITION: ${our_company?.name || 'Not found'}`,
  our_company ? [
    `  G2: ${our_company.g2.rating}/5 (${our_company.g2.review_count} reviews) — Rank #${our_company.g2.category_rank}`,
    `  Capterra: ${our_company.capterra.rating}/5 (${our_company.capterra.review_count} reviews) — Rank #${our_company.capterra.category_rank}`,
    `  Top G2 tags: ${our_company.g2.top_tags.join(', ')}`,
    `  Recent G2 reviews:`,
    ...our_company.g2.recent_reviews.map(r => `    [${r.stars}★] ${r.excerpt} (${r.date})`)
  ].join('\n') : '  (no data)',
  ``,
  `COMPETITORS:`,
  ...competitors.map(c => [
    `  ${c.name}:`,
    `    G2: ${c.g2.rating}/5 (${c.g2.review_count} reviews) — Rank #${c.g2.category_rank}`,
    `    Capterra: ${c.capterra.rating}/5 (${c.capterra.review_count} reviews) — Rank #${c.capterra.category_rank}`,
    `    Recent G2 reviews:`,
    ...c.g2.recent_reviews.map(r => `      [${r.stars}★] ${r.excerpt} (${r.date})`)
  ].join('\n')),
  ``,
  `NOTE: Delta tracking requires historical snapshot storage (see README for setup).`
].join('\n');

return [{ json: { report_text: lines, companies, captured_at } }];
